if(!defined("IN_ESOTALK"))exit;function sanitize($value){if(!is_array($value)){$replace=array("&"=>"&amp;","<"=>"&lt;",">"=>"&gt;","'"=>"&#39;","\""=>"&quot;","\\"=>"&#92;","\x00"=>"");return strtr(trim($value),$replace);}else {foreach($value as $k=>$v)$value[$k]=sanitize($v);return $value;}}function desanitize($value){if(!is_array($value)){$replace=array("&amp;"=>"&","&lt;"=>"<","&gt;"=>">","&#39;"=>"'","&#039;"=>"'","&quot;"=>"\"","&#92;"=>"\\","&#092;"=>"\\");return strtr($value,$replace);}else {foreach($value as $k=>$v)$value[$k]=desanitize($v);return $value;}}function sanitizeForHTTP($value){return str_replace(array("\r","\n","%0a","%0d","%0A","%0D"),"",$value);}function sanitizeFileName($value){return preg_replace("/(?:[\/:\\\]|\.{2,}|\\x00)/","",$value);}function escapeDoubleQuotes($value){return str_replace('"','\"',$value);}function slug($string){if(!($slug=trim(preg_replace(array("/'/","/[^a-z0-9]+/"),array("","-"),strtolower(desanitize($string))),"-")))$slug="-";return substr($slug,0,63);}function highlight($text,$words){foreach($words as $word){if(!$word=trim($word))continue;$text=preg_replace("/(?<=[\s>]|^)(".preg_quote($word,"/").")(?=[\s<,.?!:]|$)/i","<span class='highlight'>$1</span>",$text);}return $text;}function processRequestURI($requestURI){global $config;$path=parse_url($config["baseURL"]);$path=$path["path"];$request=preg_replace("|^$path|","",$requestURI);if(($pos=strpos($request,"?"))!==false)$request=substr_replace($request,"",$pos);$parts=explode("/",trim(urldecode($request),"/"));if($parts[0]=="index.php")array_shift($parts);return $parts;}function generateRandomString($numOfChars){$possibleChars="abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ1234567890~!@#%^&*()_+=-{}[]:;<,>.?/`";$salt="";for($i=0;$i<$numOfChars;$i++)$salt.=$possibleChars[rand(0,strlen($possibleChars)-1)];return $salt;}function undoMagicQuotes($value){if(!is_array($value))return stripslashes($value);else {foreach($value as $k=>$v)$value[$k]=undoMagicQuotes($v);retu